import { GameConfig }          from './config/GameConfig';
import { FieldModel }          from './core/FieldModel';
import { GameSession }         from './core/GameSession';
import {
    BoosterType, CellData, GridPosition, SuperTileType,
}                              from './core/Types';
import { SuperTileResolver }   from './strategies/SuperTileStrategy';
import {
    IInputContext, IInputState,
    IdleState, LockedState,
    BombBoosterState,
    TeleportFirstPickState,
    TeleportSecondPickState,
}                              from './input/InputState';
import FieldRenderer           from './rendering/FieldRenderer';
import { HUDPresenter }        from './rendering/HUDPresenter';

const { ccclass, property } = cc._decorator;

/**
 * **Facade** — single entry‑point component for the Blast game.
 *
 * Attach to the **Canvas** node; sprite references are assigned in the
 * Cocos Creator Inspector.  Everything else (child node discovery,
 * sub‑system wiring) happens automatically.
 *
 * Delegates input handling to **State** objects (see input/InputState.ts)
 * and super‑tile effect resolution to **Strategy** objects
 * (see strategies/SuperTileStrategy.ts).
 */
@ccclass
export default class BlastGame extends cc.Component implements IInputContext {

    // ── Inspector‑assigned sprites ────────────────────────
    @property({
        type: [cc.SpriteFrame],
        tooltip: 'Тайлы: Blue, Red, Green, Yellow, Purple',
    })
    tileSprites: cc.SpriteFrame[] = [];

    @property({ type: cc.SpriteFrame, tooltip: 'block_rockets_horisontal → row clear' })
    superRowSprite: cc.SpriteFrame = null!;

    @property({ type: cc.SpriteFrame, tooltip: 'block_rakets → column clear' })
    superColSprite: cc.SpriteFrame = null!;

    @property({ type: cc.SpriteFrame, tooltip: 'block_bomb → radius bomb' })
    superBombSprite: cc.SpriteFrame = null!;

    @property({ type: cc.SpriteFrame, tooltip: 'block_bomb_max → field clear' })
    superFieldSprite: cc.SpriteFrame = null!;

    @property({ type: cc.Font, tooltip: 'Marvin.ttf — основной шрифт игры' })
    gameFont: cc.Font = null!;

    // ── Sub‑systems ───────────────────────────────────────
    private field:    FieldModel    = null!;
    private session:  GameSession   = null!;
    private renderer: FieldRenderer = null!;
    private hud:      HUDPresenter  = null!;

    // ── State machine (State pattern) ─────────────────────
    private inputState: IInputState = new LockedState();

    // ── Booster panel references (for visual feedback) ────
    private bombPanel:  cc.Node | null = null;
    private telePanel:  cc.Node | null = null;
    private bombPanelBaseScale  = 1;
    private telePanelBaseScale  = 1;

    // ── Smooth score counter state ─────────────────────
    private _scoreDisplayed = 0;
    private _scoreTarget    = 0;
    private _scoreFrom      = 0;
    private _scoreElapsed   = 0;
    private _scoreDuration  = 0;

    // ══════════════════════════════════════════════════════
    //  Lifecycle
    // ══════════════════════════════════════════════════════

    protected onLoad(): void {
        this.initSystems();
    }

    /** Called one frame after onLoad — safe to start async work. */
    protected start(): void {
        this.beginGame();
    }

    /** Drives the smooth score counter every frame. */
    protected update(dt: number): void {
        if (this._scoreDuration <= 0 || this._scoreDisplayed === this._scoreTarget) return;

        this._scoreElapsed += dt;
        const t = Math.min(1, this._scoreElapsed / this._scoreDuration);
        // ease‑out cubic for a satisfying deceleration
        const ease = 1 - Math.pow(1 - t, 3);
        this._scoreDisplayed = Math.round(
            this._scoreFrom + (this._scoreTarget - this._scoreFrom) * ease,
        );
        this.hud.setScore(this._scoreDisplayed, this.session.getTargetScore());
    }

    /** Synchronous wiring of all sub‑systems. */
    private initSystems(): void {
        this.field   = new FieldModel();
        this.session = new GameSession();

        this.wireRenderer();
        this.wireHUD();
        this.wireBoosterButtons();

        this.ensureValidBoard();
        this.renderer.createAllTiles(this.field.getGrid());

        // Force‑set score label to «0/target» immediately (before animation loop kicks in)
        this.hud.setScore(0, this.session.getTargetScore());
        this.refreshHUD();
        // Input stays locked until the initial animation finishes
    }

    /** Async intro animation → then unlock input. */
    private async beginGame(): Promise<void> {
        await this.renderer.animateInitialAppearance();
        this.transitionTo(new IdleState());
    }

    // ══════════════════════════════════════════════════════
    //  IInputContext implementation
    // ══════════════════════════════════════════════════════

    public transitionTo(state: IInputState): void {
        this.inputState = state;
        this.updateBoosterPanelVisuals();
    }

    public getCellAt(row: number, col: number): CellData | null {
        return this.field.getCell(row, col);
    }

    public findGroup(row: number, col: number): GridPosition[] {
        return this.field.findGroup(row, col);
    }

    public getBoosterCount(type: BoosterType): number {
        return this.session.getBoosterCount(type);
    }

    public highlightTile(row: number, col: number, on: boolean): void {
        this.renderer.setTileHighlight(row, col, on);
    }

    public clearHighlights(): void {
        this.renderer.clearAllHighlights();
    }

    // ── Command executors (called by states) ──────────────

    public executeGroupMatch(row: number, col: number): void {
        this.transitionTo(new LockedState());
        this.processGroupMatch(row, col);
    }

    public executeSuperTileActivation(row: number, col: number, type: SuperTileType): void {
        this.transitionTo(new LockedState());
        this.processSuperTile(row, col, type);
    }

    public executeBombBooster(row: number, col: number): void {
        if (!this.session.consumeBooster(BoosterType.Bomb)) return;
        this.transitionTo(new LockedState());
        this.processBombBooster(row, col);
    }

    public executeTeleportSwap(a: GridPosition, b: GridPosition): void {
        if (!this.session.consumeBooster(BoosterType.Teleport)) {
            this.transitionTo(new IdleState());
            return;
        }
        this.transitionTo(new LockedState());
        this.processTeleport(a, b);
    }

    // ══════════════════════════════════════════════════════
    //  Core async flows
    // ══════════════════════════════════════════════════════

    private async processGroupMatch(row: number, col: number): Promise<void> {
        const cell  = this.field.getCell(row, col)!;
        const group = this.field.findGroup(row, col);
        const color = cell.color;
        const superType = SuperTileResolver.determineType(group.length);
        const points = this.session.calcGroupScore(group.length);

        this.field.removeTiles(group);
        await this.renderer.animateDestroy(group);

        // Floating score popup right where tiles vanished
        this.renderer.showFloatingScore(row, col, points, this.gameFont);

        if (superType !== SuperTileType.None) {
            this.field.placeSuperTile(row, col, color, superType);
            this.renderer.placeSuperTile(row, col, { color, superType });
            await this.renderer.animateSingleSpawn(row, col);
        }

        await this.settleField();

        this.session.addScore(points);
        this.session.consumeMove();
        this.refreshHUD();

        await this.endOfTurn();
    }

    private async processSuperTile(row: number, col: number, type: SuperTileType): Promise<void> {
        const seeds = SuperTileResolver.resolve(type, this.field, row, col);
        seeds.push({ row, col });
        const affected = SuperTileResolver.collectChained(this.field, seeds);
        const points   = this.session.calcEffectScore(affected.length);

        this.field.removeTiles(affected);

        // Pick the right animation for each super‑tile variant
        const center = { row, col };
        switch (type) {
            case SuperTileType.RowClear:
                await this.renderer.animateRowClear(center, affected);
                break;
            case SuperTileType.ColumnClear:
                await this.renderer.animateColumnClear(center, affected);
                break;
            case SuperTileType.RadiusBomb:
                await this.renderer.animateBombBlast(center, affected);
                break;
            case SuperTileType.FieldClear:
                await this.renderer.animateFieldClear(center, affected);
                break;
            default:
                await this.renderer.animateDestroy(affected);
        }

        this.renderer.showFloatingScore(row, col, points, this.gameFont);

        await this.settleField();

        this.session.addScore(points);
        this.session.consumeMove();
        this.refreshHUD();

        await this.endOfTurn();
    }

    private async processBombBooster(row: number, col: number): Promise<void> {
        const seeds    = this.field.positionsInRadius(row, col, GameConfig.BOMB_RADIUS);
        const affected = SuperTileResolver.collectChained(this.field, seeds);
        const points   = this.session.calcEffectScore(affected.length);

        this.field.removeTiles(affected);
        await this.renderer.animateBombBlast({ row, col }, affected);

        this.renderer.showFloatingScore(row, col, points, this.gameFont);

        await this.settleField();

        this.session.addScore(points);
        this.refreshHUD();                // booster does NOT consume a move

        await this.endOfTurn();
    }

    private async processTeleport(a: GridPosition, b: GridPosition): Promise<void> {
        this.field.swapTiles(a, b);
        await this.renderer.animateSwap(a, b);

        this.refreshHUD();                // teleport does NOT consume a move
        this.transitionTo(new IdleState());
    }

    // ══════════════════════════════════════════════════════
    //  Shared helpers
    // ══════════════════════════════════════════════════════

    private async settleField(): Promise<void> {
        const grav = this.field.applyGravity();
        await this.renderer.animateGravity(grav);

        const spawned = this.field.fillEmpty();
        await this.renderer.animateSpawn(spawned);
    }

    private async endOfTurn(): Promise<void> {
        if (this.session.checkWin())  { this.showResult(true);  return; }
        if (this.session.checkLose()) { this.showResult(false); return; }

        await this.autoShuffle();

        if (!this.session.isGameOver()) {
            this.transitionTo(new IdleState());
        }
    }

    private async autoShuffle(): Promise<void> {
        while (!this.field.hasValidMoves()) {
            if (!this.session.consumeShuffle()) {
                this.session.forceLose();
                this.showResult(false);
                return;
            }
            this.field.shuffle();
            await this.renderer.animateShuffle(this.field.getGrid());
        }
    }

    private ensureValidBoard(): void {
        while (!this.field.hasValidMoves()) this.field.shuffle();
    }

    private refreshHUD(): void {
        this.animateScoreTo(this.session.getScore());
        this.hud.setMoves(this.session.getMovesRemaining());
        this.hud.setBombCount(this.session.getBoosterCount(BoosterType.Bomb));
        this.hud.setTeleportCount(this.session.getBoosterCount(BoosterType.Teleport));
    }

    /** Kick off (or restart) the smooth score counter towards `target`. */
    private animateScoreTo(target: number): void {
        if (target === this._scoreTarget && this._scoreDisplayed === target) return;
        this._scoreFrom     = this._scoreDisplayed;
        this._scoreTarget   = target;
        this._scoreElapsed  = 0;
        const diff = Math.abs(target - this._scoreFrom);
        // Duration scales with difference but stays within reasonable bounds
        this._scoreDuration = Math.max(
            GameConfig.SCORE_COUNTER_DURATION,
            Math.min(0.9, diff / 300),
        );
    }

    // ══════════════════════════════════════════════════════
    //  Booster panel visual feedback
    // ══════════════════════════════════════════════════════

    /**
     * Pulse the active booster panel; reset the other.
     * Called every time inputState changes.
     */
    private updateBoosterPanelVisuals(): void {
        const isBomb = this.inputState instanceof BombBoosterState;
        const isTele = this.inputState instanceof TeleportFirstPickState
                    || this.inputState instanceof TeleportSecondPickState;

        this.setBoosterPanelActive(this.bombPanel, this.bombPanelBaseScale, isBomb);
        this.setBoosterPanelActive(this.telePanel, this.telePanelBaseScale, isTele);
    }

    private setBoosterPanelActive(panel: cc.Node | null, baseScale: number, active: boolean): void {
        if (!panel) return;
        cc.Tween.stopAllByTarget(panel);

        if (active) {
            // Pulsing glow while armed
            cc.tween(panel)
                .repeatForever(
                    cc.tween()
                        .to(0.35, { scale: baseScale * 1.1 }, { easing: 'sineInOut' })
                        .to(0.35, { scale: baseScale * 0.95 }, { easing: 'sineInOut' }),
                )
                .start();
        } else {
            panel.scale = baseScale;
        }
    }

    // ══════════════════════════════════════════════════════
    //  Wiring (auto‑discover scene nodes)
    // ══════════════════════════════════════════════════════

    private wireRenderer(): void {
        const panel = cc.find('GamePanel', this.node)!;
        this.renderer = panel.addComponent(FieldRenderer);

        const superMap = new Map<SuperTileType, cc.SpriteFrame>();
        if (this.superRowSprite)   superMap.set(SuperTileType.RowClear,    this.superRowSprite);
        if (this.superColSprite)   superMap.set(SuperTileType.ColumnClear, this.superColSprite);
        if (this.superBombSprite)  superMap.set(SuperTileType.RadiusBomb,  this.superBombSprite);
        if (this.superFieldSprite) superMap.set(SuperTileType.FieldClear,  this.superFieldSprite);

        this.renderer.init(
            GameConfig.GRID_ROWS, GameConfig.GRID_COLS,
            this.tileSprites, superMap,
            (r, c) => this.inputState.onCellClick(this, r, c),
        );
    }

    private wireHUD(): void {
        const label = (path: string): cc.Label | null => {
            const n = cc.find(path, this.node);
            return n ? n.getComponent(cc.Label) : null;
        };

        const scoreLabel = label('ScorePanel/ScoreTxt');
        const movesLabel = label('ScorePanel/MovesPanel/Moves');
        const bombLabel  = label('BoosterBombPanel/TeleportTxt');
        const teleLabel  = label('BoosterTeleportPanel/TeleportTxt');

        // Auto‑detect font from existing scene labels (Marvin.ttf)
        if (!this.gameFont) {
            for (const l of [scoreLabel, movesLabel, bombLabel, teleLabel]) {
                if (l && l.font) { this.gameFont = l.font; break; }
            }
        }

        this.hud = new HUDPresenter(
            scoreLabel, movesLabel, bombLabel, teleLabel,
            this.gameFont || undefined,
        );
    }

    private wireBoosterButtons(): void {
        this.bombPanel = cc.find('BoosterBombPanel', this.node);
        this.telePanel = cc.find('BoosterTeleportPanel', this.node);

        if (this.bombPanel) {
            this.bombPanelBaseScale = this.bombPanel.scale;
            this.bombPanel.on(cc.Node.EventType.TOUCH_START,
                (e: cc.Event.EventTouch) => e.stopPropagation(), this);
            this.bombPanel.on(cc.Node.EventType.TOUCH_END,
                (e: cc.Event.EventTouch) => {
                    e.stopPropagation();
                    this.inputState.onBoosterBombClick(this);
                }, this);
        }
        if (this.telePanel) {
            this.telePanelBaseScale = this.telePanel.scale;
            this.telePanel.on(cc.Node.EventType.TOUCH_START,
                (e: cc.Event.EventTouch) => e.stopPropagation(), this);
            this.telePanel.on(cc.Node.EventType.TOUCH_END,
                (e: cc.Event.EventTouch) => {
                    e.stopPropagation();
                    this.inputState.onBoosterTeleportClick(this);
                }, this);
        }
    }

    // ══════════════════════════════════════════════════════
    //  Result popup (programmatic)
    // ══════════════════════════════════════════════════════

    private showResult(isWin: boolean): void {
        this.transitionTo(new LockedState());

        const W = this.node.width;
        const H = this.node.height;

        // ── Overlay (fades in) ─────────────────────────────
        const overlay = new cc.Node('ResultOverlay');
        overlay.parent = this.node;
        overlay.setContentSize(W, H);
        overlay.setPosition(0, 0);
        overlay.opacity = 0;

        const bg = overlay.addComponent(cc.Graphics);
        bg.fillColor = new cc.Color(0, 0, 0, 180);
        bg.rect(-W / 2, -H / 2, W, H);
        bg.fill();

        overlay.on(cc.Node.EventType.TOUCH_START, (e: cc.Event.EventTouch) => e.stopPropagation());
        overlay.on(cc.Node.EventType.TOUCH_END,   (e: cc.Event.EventTouch) => e.stopPropagation());

        cc.tween(overlay).to(0.35, { opacity: 255 }).start();

        // ── Title — drops from top with bounce ─────────────
        const title = this.makeLabel(overlay, 0, 350,
            isWin ? 'ПОБЕДА!' : 'ПОРАЖЕНИЕ!', 80);
        title.color = isWin ? cc.color(255, 220, 50) : cc.color(255, 80, 80);
        title.scale = 0;
        cc.tween(title)
            .delay(0.15)
            .to(0.45, { scale: 1.15, y: 130 }, { easing: 'backOut' })
            .to(0.12, { scale: 1.0 },          { easing: 'sineInOut' })
            .start();

        // ── Win: gentle repeating pulse on title ───────────
        if (isWin) {
            cc.tween(title)
                .delay(0.75)
                .repeatForever(
                    cc.tween()
                        .to(0.8, { scale: 1.06 }, { easing: 'sineInOut' })
                        .to(0.8, { scale: 1.0 },  { easing: 'sineInOut' }),
                )
                .start();
        }

        // ── Score — scales in ──────────────────────────────
        const scoreNode = this.makeLabel(overlay, 0, 20,
            `Очки: ${this.session.getScore()} / ${this.session.getTargetScore()}`, 50);
        scoreNode.scale   = 0;
        scoreNode.opacity = 0;
        cc.tween(scoreNode)
            .delay(0.50)
            .to(0.35, { scale: 1, opacity: 255 }, { easing: 'backOut' })
            .start();

        // ── Button — slides up from below ──────────────────
        const btn = new cc.Node('RestartBtn');
        btn.parent = overlay;
        btn.setPosition(0, -280);
        btn.setContentSize(340, 90);
        btn.setAnchorPoint(0.5, 0.5);
        btn.scale = 0;

        const g = btn.addComponent(cc.Graphics);
        g.fillColor = isWin ? new cc.Color(60, 170, 60) : new cc.Color(170, 60, 60);
        g.roundRect(-170, -45, 340, 90, 16);
        g.fill();

        this.makeLabel(btn, 0, 0, 'ЗАНОВО', 52);

        cc.tween(btn)
            .delay(0.70)
            .to(0.40, { scale: 1, y: -100 }, { easing: 'backOut' })
            .start();

        btn.on(cc.Node.EventType.TOUCH_END, () => {
            // Shrink overlay before destroying
            cc.tween(overlay)
                .to(0.2, { opacity: 0, scale: 0.9 })
                .call(() => { overlay.destroy(); this.restart(); })
                .start();
        }, this);

        // ── Win confetti burst ─────────────────────────────
        if (isWin) this.spawnConfetti(overlay);
    }

    /**
     * Burst of coloured confetti squares radiating from centre.
     * Pure Graphics — no extra assets needed.
     */
    private spawnConfetti(parent: cc.Node): void {
        const palette = [
            cc.color(255, 220, 50),
            cc.color(255, 100, 40),
            cc.color(80, 210, 255),
            cc.color(255, 70, 170),
            cc.color(100, 255, 100),
            cc.color(200, 130, 255),
        ];

        const COUNT = 24;
        for (let i = 0; i < COUNT; i++) {
            const spark = new cc.Node('Confetti');
            spark.parent = parent;
            spark.setPosition(0, 130);      // origin near the title
            spark.scale   = 0;
            spark.opacity = 255;

            const sz = 8 + Math.random() * 8;
            const gfx = spark.addComponent(cc.Graphics);
            gfx.fillColor = palette[i % palette.length];
            gfx.roundRect(-sz / 2, -sz / 2, sz, sz, 2);
            gfx.fill();

            const angle  = (Math.PI * 2 * i) / COUNT + (Math.random() - 0.5) * 0.4;
            const radius = 220 + Math.random() * 260;
            const tx     = Math.cos(angle) * radius;
            const ty     = Math.sin(angle) * radius + 130;
            const delay  = 0.35 + Math.random() * 0.25;
            const dur    = 0.6  + Math.random() * 0.5;
            const spin   = (Math.random() - 0.5) * 720;

            cc.tween(spark)
                .delay(delay)
                .to(0.08, { scale: 1 })
                .to(dur, {
                    x: tx, y: ty,
                    opacity: 0,
                    scale: 0.2,
                    angle: spin,
                } as any, { easing: 'sineOut' })
                .call(() => spark.destroy())
                .start();
        }
    }

    private makeLabel(parent: cc.Node, x: number, y: number, text: string, size: number): cc.Node {
        const n = new cc.Node();
        n.parent = parent;
        n.setPosition(x, y);
        const l      = n.addComponent(cc.Label);
        l.string     = text;
        l.fontSize   = size;
        l.lineHeight = size + 10;
        l.horizontalAlign = cc.Label.HorizontalAlign.CENTER;
        l.verticalAlign   = cc.Label.VerticalAlign.CENTER;
        if (this.gameFont) {
            l.font          = this.gameFont;
            l.useSystemFont = false;
        }
        n.color = cc.Color.WHITE;
        return n;
    }

    // ══════════════════════════════════════════════════════
    //  Restart
    // ══════════════════════════════════════════════════════

    private async restart(): Promise<void> {
        this.transitionTo(new LockedState());

        // Shrink existing tiles
        await this.renderer.animateDismissAll();
        this.renderer.clearAllTiles();

        // Rebuild model
        this.field   = new FieldModel();
        this.session = new GameSession();
        this.ensureValidBoard();

        // Reset smooth counter and immediately push «0» into the label
        this._scoreDisplayed = 0;
        this._scoreTarget    = 0;
        this._scoreFrom      = 0;
        this._scoreDuration  = 0;
        this.hud.setScore(0, this.session.getTargetScore());

        // Rebuild view
        this.renderer.createAllTiles(this.field.getGrid());
        this.refreshHUD();

        // Cascade appearance → unlock
        await this.renderer.animateInitialAppearance();
        this.transitionTo(new IdleState());
    }
}
